css:
.loader {color: var(--loader-color, #0ea5e9);
  --loader-secondary-color: #67e8f9;
  --loader-bg: #ffffff;
   width: 68px;
   aspect-ratio: 1;
   border: 8px solid currentColor;
   box-sizing: border-box;
   background: radial-gradient(farthest-side,currentColor 98%,#0000) 50%/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) 50%/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) 50%/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) 50%/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) 50%/20px 20px, linear-gradient(currentColor 0 0) 50%/100% 10px, linear-gradient(currentColor 0 0) 50%/10px 100%, currentColor;
   background-repeat: no-repeat;
   filter: blur(4px) contrast(10);
   animation: l13 0.8s infinite;
}
@keyframes l13  {
  100% {background-position:50% -20px,-20px 50%,60px 50%,50% 60px,50%,50%,50%}
}
